            "openai": "https://api.openai.com/v1"}
md = {}
try: md = json.load(open(os.path.join(home, ".cache/opencode/models.json"), encoding="utf-8"))
except Exception: pass

d = {}
if os.path.exists(path):
    try:
        d = json.load(open(path, encoding="utf-8"))
        if not isinstance(d, dict): print("   (skipping opencode.json: not an object)"); sys.exit(0)
    except json.JSONDecodeError:
        print("   (skipping opencode.json: not valid JSON — edit manually)"); sys.exit(0)
    shutil.copy2(path, path + ".pre-cc-trace.bak")

